// ROME-TAG: 0xHEALTH42 — strict health check
import http from 'node:http';
import { setTimeout as sleep } from 'node:timers/promises';
export async function strictHealthCheck(url, opts = {}) {
    const timeoutMs = opts.timeoutMs ?? 6000;
    const attemptDelayMs = opts.attemptDelayMs ?? 300;
    const maxAttempts = opts.maxAttempts ?? 10;
    const deadline = Date.now() + timeoutMs;
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        const ok = await checkOnce(url, opts.port);
        if (ok)
            return true;
        if (Date.now() > deadline)
            return false;
        await sleep(attemptDelayMs * attempt);
    }
    return false;
}
function checkOnce(url, port) {
    return new Promise((resolve) => {
        try {
            const u = new URL(url, 'http://127.0.0.1');
            const req = http.get({ timeout: 800, hostname: u.hostname, path: u.pathname + (u.search ?? ''), port }, (res) => {
                const healthy = res.statusCode && res.statusCode >= 200 && res.statusCode < 400;
                res.resume?.();
                resolve(Boolean(healthy));
            });
            req.on('timeout', () => {
                req.destroy();
                resolve(false);
            });
            req.on('error', () => resolve(false));
        }
        catch {
            resolve(false);
        }
    });
}
